3_real_world_example.code:
//  Synchronous — instant operations, fine on the stack
const items = [1, 2, 3];
const doubled = items.map(x => x * 2); // completes immediately
console.log(doubled); // [2, 4, 6]

//  Asynchronous — slow operation, handed to browser
console.log('Fetching...');
fetch('/api/data')
  .then(res => res.json())
  .then(data => console.log('Got:', data)); // runs LATER
console.log('Still running sync code...'); // runs BEFORE fetch resolves

// Output:
// Fetching...
// Still running sync code...
// Got: { ... }    ← arrives after sync code finishes

